import React, { useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import axios from 'axios';
import toast from 'react-hot-toast';

export default function FigmaRegisterPage() {
    const [formData, setFormData] = useState({
        username: '',
        email: '',
        password: '',
        password2: ''
    });
    const [loading, setLoading] = useState(false);
    const navigate = useNavigate();

    const handleSubmit = async (e) => {
        e.preventDefault();
        if (formData.password !== formData.password2) {
            toast.error('Пароли не совпадают');
            return;
        }
        setLoading(true);
        try {
            await axios.post('http://localhost:8000/api/users/register/', formData);
            toast.success('Регистрация успешна! Теперь войдите');
            navigate('/login');
        } catch (error) {
            toast.error(error.response?.data?.password?.[0] || 'Ошибка регистрации');
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="register-container">
            {/* Фоновое изображение - вставьте ваш фон сюда */}
            {/* ПОМЕСТИТЕ ФОНОВОЕ ИЗОБРАЖЕНИЕ В: public/images/sigma-images/bg-pattern.png */}
            <div className="register-bg">
                <img src="/images/sigma-images/yadro_pattern_1-1-2.png" alt="background" className="register-bg-image" />
            </div>

            <div className="register-card">
                {/* Логотип */}
                <div className="register-logo">
                    {/* SVG иконки логотипа - вставьте сюда */}
                    {/* ИЗОБРАЖЕНИЯ ЛОГОТИПА В: public/images/sigma-images/vector-5.svg ... vector-13.svg */}
                    <div className="logo-icon"></div>
                    <h1 className="register-title">VideoPlatform</h1>
                </div>

                <h2 className="register-heading">Создать аккаунт</h2>

                <form onSubmit={handleSubmit} className="register-form">
                    <div className="input-group">
                        <input
                            type="text"
                            placeholder="Имя пользователя"
                            value={formData.username}
                            onChange={(e) => setFormData({...formData, username: e.target.value})}
                            className="register-input"
                            required
                        />
                    </div>

                    <div className="input-group">
                        <input
                            type="email"
                            placeholder="Email"
                            value={formData.email}
                            onChange={(e) => setFormData({...formData, email: e.target.value})}
                            className="register-input"
                            required
                        />
                    </div>

                    <div className="input-group">
                        <input
                            type="password"
                            placeholder="Пароль"
                            value={formData.password}
                            onChange={(e) => setFormData({...formData, password: e.target.value})}
                            className="register-input"
                            required
                        />
                    </div>

                    <div className="input-group">
                        <input
                            type="password"
                            placeholder="Подтвердите пароль"
                            value={formData.password2}
                            onChange={(e) => setFormData({...formData, password2: e.target.value})}
                            className="register-input"
                            required
                        />
                    </div>

                    <button type="submit" disabled={loading} className="register-btn">
                        {loading ? 'Регистрация...' : 'Зарегистрироваться'}
                    </button>
                </form>

                <p className="register-footer">
                    Уже есть аккаунт? <Link to="/login">Войти</Link>
                </p>
            </div>
        </div>
    );
}
